// mag/arcsec^2 - the published values.
// Cite: Falchi et al. 2016, Science Advances 2, e1600377.
export const SKYGLOW_W = 720;
export const SKYGLOW_H = 290;
const B64 =
  '';
const bin =
  typeof atob === 'function'
    ? atob(B64)
    : Buffer.from(B64, 'base64').toString('binary');
export const SKYGLOW = Uint8Array.from(bin, (c) => c.charCodeAt(0));
